// viewport-mobile-view — Phone-optimized viewport with bottom action bar.
// Replaces viewport-desktop-view on touch devices (screens: { touch: true }).

export async function render(item, api) {
  // === URL root resolution (same logic as viewport-view) ===
  const params = new URLSearchParams(window.location.search);
  const urlRoot = params.get('root');
  const storedSpec = item.attachments?.[0];
  const storedRootId = typeof storedSpec === 'string' ? storedSpec : storedSpec?.id;

  let rootId = storedRootId;
  let rootSpec = storedSpec;

  if (urlRoot && urlRoot !== storedRootId) {
    try {
      await api.get(urlRoot);
      await api.set(
        { ...item, attachments: [{ id: urlRoot }], modified: Date.now() },
        { silent: true }
      );
      rootId = urlRoot;
      rootSpec = { id: urlRoot };
    } catch {
      // URL root not found, keep stored
    }
  }

  // Honor the user's explicit view choice if it matches this environment,
  // otherwise let resolveView pick an appropriate view.
  const storedViewId = rootSpec?.view?.type || rootSpec?.view || rootSpec?.renderer || null;
  let rootViewId = null;
  if (storedViewId) {
    try {
      const vpRendering = await api.require('viewport-rendering');
      const rs = vpRendering.getRendering();
      const storedView = await api.get(storedViewId);
      if (rs.viewMatchesEnv(storedView)) rootViewId = storedViewId;
    } catch { /* view not found, let resolveView handle it */ }
  }

  // === Set document title ===
  if (rootId) {
    try {
      const rootItem = await api.get(rootId);
      const name = rootItem.content?.title || rootItem.name || rootId.slice(0, 8);
      document.title = `${name} - Hobson`;
    } catch {
      document.title = 'Hobson';
    }
  } else {
    document.title = 'Hobson';
  }
  // Sync to Tauri window title
  if (window.__TAURI__?.window?.getCurrentWindow) {
    window.__TAURI__.window.getCurrentWindow().setTitle(document.title).catch(() => {});
  }

  // === Selection state ===
  let selectedItemId = null;
  let selectedElement = null;

  function findItemElement(target) {
    return target.closest('[data-parent-id][data-item-id]')
      || target.closest('[data-item-id]');
  }

  function updateSelectionVisual() {
    container.querySelectorAll('[data-item-id].item-selected').forEach(el =>
      el.classList.remove('item-selected')
    );
    if (selectedElement) selectedElement.classList.add('item-selected');
  }

  function selectItem(iid, el) {
    selectedItemId = iid;
    selectedElement = el;
    api.viewport.select(iid, el?.getAttribute('data-parent-id'));
    updateSelectionVisual();
  }

  function clearSelection() {
    selectedItemId = null;
    selectedElement = null;
    api.viewport.clearSelection();
    updateSelectionVisual();
  }

  // === Build DOM ===
  const container = api.createElement('div', {
    class: 'mobile-viewport',
    style: 'display:flex; flex-direction:column; height:100%; position:relative;'
  });

  // --- Content area ---
  const contentArea = api.createElement('div', {
    class: 'mobile-viewport-content',
    style: 'flex:1; overflow:auto; display:flex; flex-direction:column; min-height:0;'
  });

  if (rootId) {
    const decorator = (dom, itemId, theItem) => {
      dom.setAttribute('data-item-id', itemId);
      const iname = theItem?.name || theItem?.content?.title || itemId.slice(0, 8);
      let typeName;
      try {
        const ti = theItem?.type;
        typeName = ti ? ti.slice(0, 8) : '?';
      } catch { typeName = '?'; }
      dom.setAttribute('title', `${iname} (${typeName})`);
    };

    const rootDom = await api.renderItem(rootId, rootViewId, {
      decorator,
      onCycle: () => {
        const el = api.createElement('div', {
          style: 'padding:20px; color:var(--color-text-secondary); font-style:italic; text-align:center;'
        });
        el.textContent = rootId.slice(0, 8) + ' (cycle)';
        return el;
      }
    });
    if (rootDom) {
      rootDom.style.cssText = 'flex:1; min-height:0; display:flex; flex-direction:column;';
      contentArea.appendChild(rootDom);
    }
  } else {
    const empty = api.createElement('div', {
      style: 'padding:40px; text-align:center; color:var(--color-text-secondary); flex:1; display:flex; align-items:center; justify-content:center;'
    });
    empty.innerHTML = 'No item selected.<br><br>Tap Search to find items.';
    contentArea.appendChild(empty);
  }

  // Tap to select
  contentArea.addEventListener('click', (e) => {
    hideSheet();
    const el = findItemElement(e.target);
    if (el) {
      selectItem(el.getAttribute('data-item-id'), el);
      e.stopPropagation();
    } else {
      clearSelection();
    }
  });

  container.appendChild(contentArea);

  // --- Bottom sheet (context menu) ---
  const backdrop = api.createElement('div', {
    class: 'mobile-bottom-sheet-backdrop',
    style: 'display:none; position:fixed; top:0; left:0; right:0; bottom:0; background:rgba(0,0,0,0.4); z-index:10000;'
  });

  const sheet = api.createElement('div', {
    class: 'mobile-bottom-sheet',
    style: 'position:fixed; bottom:0; left:0; right:0; max-height:60vh; background:var(--color-bg-surface); border-radius:12px 12px 0 0; overflow-y:auto; z-index:10001; padding-bottom:env(safe-area-inset-bottom);'
  });

  const handle = api.createElement('div', {
    style: 'width:36px; height:4px; background:var(--color-border); border-radius:2px; margin:8px auto 4px;'
  });
  sheet.appendChild(handle);

  const sheetBody = api.createElement('div', { class: 'mobile-sheet-body' });
  sheet.appendChild(sheetBody);
  backdrop.appendChild(sheet);

  function hideSheet() {
    backdrop.style.display = 'none';
    sheetBody.innerHTML = '';
  }

  backdrop.addEventListener('click', (e) => {
    if (e.target === backdrop) hideSheet();
  });

  async function showContextMenu(itemId) {
    sheetBody.innerHTML = '';
    const menuLib = await api.require('context-menu-lib');
    const dismiss = () => {
      hideSheet();
    };
    const menuEl = await menuLib.buildItemMenu(api, itemId, { onDismiss: dismiss, rootId });
    // Override desktop positioning for bottom sheet
    menuEl.style.cssText = 'position:static; display:block; box-shadow:none; max-width:none; border:none; min-width:0; padding:0;';
    sheetBody.appendChild(menuEl);
    backdrop.style.display = 'block';
  }

  container.appendChild(backdrop);

  // --- Overlay rendering (search palette, etc.) ---
  const overlaySpecs = (item.attachments || []).slice(1);
  for (const spec of overlaySpecs) {
    const oid = typeof spec === 'string' ? spec : spec.id;
    const wrapper = api.createElement('div', {
      style: 'position:fixed; top:0; left:0; right:0; bottom:0; background:rgba(0,0,0,0.5); display:flex; align-items:flex-start; justify-content:center; padding-top:5vh; z-index:10000000;'
    });
    const modal = api.createElement('div', {
      style: 'background:var(--color-bg-surface); border-radius:8px; width:92vw; max-height:80vh; display:flex; flex-direction:column; box-shadow:0 4px 20px rgba(0,0,0,0.3); overflow:auto;'
    });

    const closeOverlay = async () => {
      await api.detach(item.id, oid);
      (await api.require('viewport-rendering')).getRendering()?.renderViewport();
    };
    wrapper.addEventListener('click', (e) => {
      if (e.target === wrapper) closeOverlay();
    });
    document.addEventListener('keydown', function escHandler(e) {
      if (e.key === 'Escape') {
        e.preventDefault();
        document.removeEventListener('keydown', escHandler);
        closeOverlay();
      }
    });

    const childDom = await api.renderItem(oid);
    if (childDom) modal.appendChild(childDom);

    wrapper.appendChild(modal);
    container.appendChild(wrapper);

    setTimeout(() => {
      const input = modal.querySelector('input');
      if (input) input.focus();
    }, 0);
  }

  // --- Bottom action bar ---
  const actionBar = api.createElement('div', {
    class: 'mobile-action-bar',
    style: [
      'display:flex', 'background:var(--color-bg-surface)',
      'border-top:1px solid var(--color-border)',
      'padding-bottom:env(safe-area-inset-bottom)',
      'flex-shrink:0'
    ].join(';')
  });

  function actionButton(label, icon, handler) {
    const btn = api.createElement('button', {
      style: [
        'flex:1', 'display:flex', 'flex-direction:column', 'align-items:center', 'justify-content:center',
        'background:none', 'border:none', 'color:var(--color-text-secondary)',
        'font-size:0.625rem', 'gap:2px', 'cursor:pointer', 'min-height:48px',
        'padding:4px 0', '-webkit-tap-highlight-color:transparent'
      ].join(';')
    });
    const iconEl = api.createElement('span', { style: 'font-size:1.25rem;' });
    iconEl.textContent = icon;
    btn.appendChild(iconEl);
    const labelEl = api.createElement('span');
    labelEl.textContent = label;
    btn.appendChild(labelEl);
    btn.addEventListener('click', handler);
    return btn;
  }

  actionBar.appendChild(actionButton('Search', '\u2315', async () => {
    await api.showItemList();
    (await api.require('viewport-rendering')).getRendering()?.renderViewport();
  }));
  actionBar.appendChild(actionButton('Edit', '\u270e', async () => {
    // Find the most specific displayed item (e.g. active tab in tabbed view),
    // falling back to the root item. Exclude items inside transclusion wrappers
    // (data-provenance-node) — those are embedded content, not navigation targets.
    const candidates = rootId ? [...document.querySelectorAll(`[data-parent-id="${rootId}"][data-item-id]`)] : [];
    const activeEl = candidates.find(el => !el.closest('[data-provenance-node]')) ?? null;
    const editId = activeEl?.getAttribute('data-item-id') || rootId;
    if (!editId) return;
    const ctxLib = await api.require('context-menu-lib');
    const editItem = await api.get(editId);
    const editView = await ctxLib.findEditableView(api, editItem.type);
    if (!editView) return;
    const vpMgr = window.kernel.moduleSystem.getCached('viewport-manager');
    await vpMgr.navigate(editId, { view: editView.id });
  }));
  actionBar.appendChild(actionButton('More', '\u22ef', () => {
    const targetId = selectedItemId || rootId;
    if (targetId) showContextMenu(targetId);
  }));
  actionBar.appendChild(actionButton('REPL', '\u2328', async () => {
    // Toggle: if already open, close it
    const existing = container.querySelector('.mobile-repl-overlay');
    if (existing) { existing.remove(); return; }

    const overlay = api.createElement('div', {
      class: 'mobile-repl-overlay',
      style: 'position:fixed; top:0; left:0; right:0; bottom:0; background:var(--color-bg-surface); display:flex; flex-direction:column; z-index:10000;'
    });

    // Header with close button
    const hdr = api.createElement('div', {
      style: 'display:flex; align-items:center; justify-content:space-between; padding:8px 12px; border-bottom:1px solid var(--color-border); flex-shrink:0; background:var(--color-bg-surface);'
    });
    const titleEl = api.createElement('span', { style: 'font-weight:600; font-size:0.875rem;' });
    titleEl.textContent = 'REPL';
    hdr.appendChild(titleEl);
    const closeBtn = api.createElement('button', {
      style: 'background:none; border:none; color:var(--color-text-secondary); font-size:1.25rem; cursor:pointer; padding:4px 8px; -webkit-tap-highlight-color:transparent;'
    });
    closeBtn.textContent = '\u2715';
    closeBtn.addEventListener('click', () => overlay.remove());
    hdr.appendChild(closeBtn);
    overlay.appendChild(hdr);

    // Override REPL layout to stack vertically on mobile
    const mobileStyle = api.createElement('style');
    mobileStyle.textContent = '.mobile-repl-overlay .repl-panel-content{flex-direction:column!important;flex:1;min-height:0} .mobile-repl-overlay .repl-input-section{flex:1!important;min-height:0} .mobile-repl-overlay .repl-vertical-splitter{display:none!important} .mobile-repl-overlay .repl-output-section{flex:1!important;min-height:0}';
    overlay.appendChild(mobileStyle);

    // Render REPL view into overlay body
    const body = api.createElement('div', { style: 'flex:1; min-height:0; display:flex; flex-direction:column;' });
    try {
      const replItem = await api.get('f1111111-0003-0003-0000-000000000000');
      const replView = await api.require('f1111111-0003-0002-0000-000000000000');
      const replDom = await replView.render(replItem, api);
      replDom.style.cssText = 'flex:1; min-height:0; display:flex; flex-direction:column;';
      body.appendChild(replDom);
    } catch (e) {
      const err = api.createElement('div', { style: 'padding:16px; color:var(--color-danger);' });
      err.textContent = 'Failed to load REPL: ' + e.message;
      body.appendChild(err);
    }
    overlay.appendChild(body);

    // Escape to close
    const escHandler = (e) => {
      if (e.key === 'Escape') { overlay.remove(); document.removeEventListener('keydown', escHandler); }
    };
    document.addEventListener('keydown', escHandler);

    container.appendChild(overlay);
    setTimeout(() => { const ta = overlay.querySelector('textarea'); if (ta) ta.focus(); }, 0);
  }));

  const syncBtn = actionButton('Sync', '\u27f3', async () => {
    const labelEl = syncBtn.querySelector('span:last-child');
    const iconEl = syncBtn.querySelector('span:first-child');
    labelEl.textContent = 'Syncing\u2026';
    syncBtn.disabled = true;
    try {
      const client = await api.require('sync-client');
      const result = await client.sync();
      iconEl.textContent = '\u2713';
      labelEl.textContent = result.accepted > 0 ? `${result.accepted} new` : 'Done';
    } catch (e) {
      iconEl.textContent = '\u2717';
      labelEl.textContent = 'Failed';
      throw e;
    }
    syncBtn.disabled = false;
    setTimeout(() => { iconEl.textContent = '\u27f3'; labelEl.textContent = 'Sync'; }, 2000);
  });
  actionBar.appendChild(syncBtn);

  container.appendChild(actionBar);

  return container;
}
